#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 65;
int n, h[MAXN], ans = 105, incr[MAXN], decr[MAXN];
void dfs(int x, int cnt1, int cnt2)
{
	if (cnt1 + cnt2 >= ans) return;
	if (x == n + 1)
	{
		ans = min(ans, cnt1 + cnt2);
		return;
	}
	int id, cop = -inf, tag = 0;
	for (int i = 1; i <= cnt1; ++i)
		if (incr[i] < h[x])
		{
			tag = 1;
			if (incr[i] > cop) id = i, cop = incr[i];
		}
	if (tag)
	{
		incr[id] = h[x];
		dfs(x + 1, cnt1, cnt2);
		incr[id] = cop;
	}
	else
	{
		incr[cnt1 + 1] = h[x];
		dfs(x + 1, cnt1 + 1, cnt2);
	}
	cop = 1e9, tag = 0;
	for (int i = 1; i <= cnt2; ++i)
		if (decr[i] > h[x])
		{
			tag = 1;
			if (decr[i] < cop)id = i, cop = decr[i];
		}
	if (tag)
	{
		decr[id] = h[x];
		dfs(x + 1, cnt1, cnt2);
		decr[id] = cop;
	}
	else
	{
		decr[cnt2 + 1] = h[x];
		dfs(x + 1, cnt1, cnt2 + 1);
	}
}
int main(void)
{
	while (cin >> n && n)
	{
		ans = 100;
		for (int i = 1; i <= n; ++i) cin >> h[i];
		dfs(1, 0, 0);
		cout << ans << '\n';
	}
	return false;
}
